## 📋 Root main.tf - ORKESTRACIJA (više nije spaghetti!)

```hcl
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region

  default_tags {
    tags = local.common_tags
  }
}

# VPC
module "vpc" {
  source = "./modules/vpc"

  name_prefix        = local.name_prefix
  vpc_cidr           = var.vpc_cidr
  availability_zones = var.availability_zones
  public_subnets    = var.public_subnets
  private_subnets   = var.private_subnets
  enable_nat_gateway = true

  tags = local.common_tags
}

# Security Groups
module "security_groups" {
  source = "./modules/security_groups"

  name_prefix = local.name_prefix
  vpc_id      = module.vpc.vpc_id

  # ALB → RDS
  rds_security_group = module.security_groups.rds_sg_id
  lambda_security_group = module.security_groups.lambda_sg_id

  tags = local.common_tags
}

# RDS
module "rds" {
  source = "./modules/rds"

  name_prefix             = local.name_prefix
  db_name                 = var.db_name
  db_username             = var.db_username
  db_password             = random_password.db_password.result

  vpc_id                  = module.vpc.vpc_id
  db_subnet_group_name    = module.vpc.db_subnet_group_name
  security_group_ids      = [module.security_groups.rds_sg_id]

  engine                  = var.rds_engine
  engine_version          = var.rds_engine_version
  instance_class          = var.rds_instance_class
  allocated_storage       = var.rds_allocated_storage

  backup_retention_period = var.backup_retention_period
  multi_az                = var.environment == "production"

  tags = local.common_tags
}

# Lambda
module "lambda" {
  source = "./modules/lambda"

  name_prefix = local.name_prefix

  runtime       = "python3.12"
  handler       = "index.handler"
  source_code   = var.lambda_source_code_path

  vpc_config = {
    subnet_ids         = module.vpc.private_subnet_ids
    security_group_ids = [module.security_groups.lambda_sg_id]
  }

  environment_variables = {
    DB_HOST     = module.rds.db_endpoint
    DB_NAME     = var.db_name
    DB_USER     = var.db_username
    ENVIRONMENT = var.environment
  }

  tags = local.common_tags
}

# Random password za RDS (jer hardcoded lozinke = SMRT)
resource "random_password" "db_password" {
  length  = 32
  special = true
}

# Spremi u Secrets Manager - NIKAD u state fajlu!
resource "aws_secretsmanager_secret" "db_password" {
  name_prefix = "${local.name_prefix}-db-password-"
}

resource "aws_secretsmanager_secret_version" "db_password" {
  secret_id      = aws_secretsmanager_secret.db_password.id
  secret_string  = random_password.db_password.result
}
```

