## 🔒 Security Groups Modul - SAME RULE, MULTIPLE GROUPS

```hcl
# modules/security_groups/main.tf

locals {
  sg_rules = {
    alb = {
      description = "ALB security group"
      ingress = [
        {
          from_port   = 80
          to_port     = 80
          protocol    = "tcp"
          cidr_blocks = ["0.0.0.0/0"]
        },
        {
          from_port   = 443
          to_port     = 443
          protocol    = "tcp"
          cidr_blocks = ["0.0.0.0/0"]
        }
      ]
      egress = [
        {
          from_port   = 0
          to_port     = 0
          protocol    = "-1"
          cidr_blocks = ["0.0.0.0/0"]
        }
      ]
    }

    lambda = {
      description = "Lambda security group"
      ingress     = []
      egress = [
        {
          from_port   = 0
          to_port     = 0
          protocol    = "-1"
          cidr_blocks = ["0.0.0.0/0"]
        }
      ]
    }

    rds = {
      description = "RDS security group"
      ingress = [
        {
          from_port       = 5432
          to_port         = 5432
          protocol        = "tcp"
          security_groups = ["lambda"]  # Reference to Lambda SG
        }
      ]
      egress = []
    }
  }
}

# Kreiraj SG za svaku aplikaciju
resource "aws_security_group" "main" {
  for_each    = local.sg_rules
  name        = "${var.name_prefix}-${each.key}-sg"
  description = each.value.description
  vpc_id      = var.vpc_id

  tags = merge(var.tags, {
    Name = "${var.name_prefix}-${each.key}-sg"
  })
}

# Ingress rules
resource "aws_vpc_security_group_ingress_rule" "main" {
  for_each = merge([
    for sg_name, sg_config in local.sg_rules : {
      for idx, rule in sg_config.ingress :
      "${sg_name}-ingress-${idx}" => merge(rule, { sg_name = sg_name })
    }
  ]...)

  security_group_id = aws_security_group.main[each.value.sg_name].id

  from_port   = each.value.from_port
  to_port     = each.value.to_port
  ip_protocol = each.value.protocol

  # Dinamički odaberi cidr_blocks ili referencu na drugi SG
  cidr_ipv4              = lookup(each.value, "cidr_blocks", null) != null ? each.value.cidr_blocks[0] : null
  referenced_group_id    = lookup(each.value, "security_groups", null) != null ? aws_security_group.main[each.value.security_groups[0]].id : null

  tags = merge(var.tags, {
    Name = "ingress-${each.value.sg_name}"
  })
}

# Outputs
output "alb_sg_id" {
  value = aws_security_group.main["alb"].id
}

output "lambda_sg_id" {
  value = aws_security_group.main["lambda"].id
}

output "rds_sg_id" {
  value = aws_security_group.main["rds"].id
}
```

