## ⚡ Lambda Modul - VPC + RDS CONNECTION

```hcl
# modules/lambda/main.tf

# Zip source code
data "archive_file" "lambda" {
  type        = "zip"
  source_dir  = var.source_code
  output_path = "${path.module}/.lambda_${data.archive_file.lambda.output_base64sha256}.zip"
}

# Lambda IAM role
resource "aws_iam_role" "lambda" {
  name = "${var.name_prefix}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Basic execution policy
resource "aws_iam_role_policy_attachment" "basic" {
  role       = aws_iam_role.lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaVPCAccessExecutionRole"
}

# Secrets Manager access za DB password
resource "aws_iam_role_policy" "secrets" {
  name = "${var.name_prefix}-lambda-secrets"
  role = aws_iam_role.lambda.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = var.db_password_secret_arn
      }
    ]
  })
}

# Lambda function
resource "aws_lambda_function" "main" {
  filename            = data.archive_file.lambda.output_path
  function_name       = "${var.name_prefix}-function"
  role                = aws_iam_role.lambda.arn
  handler             = var.handler
  source_code_hash    = data.archive_file.lambda.output_base64sha256
  runtime             = var.runtime
  timeout             = var.lambda_timeout
  memory_size         = var.lambda_memory_size

  vpc_config {
    subnet_ids         = var.vpc_config.subnet_ids
    security_group_ids = var.vpc_config.security_group_ids
  }

  environment {
    variables = var.environment_variables
  }

  tags = merge(var.tags, {
    Name = "${var.name_prefix}-function"
  })
}

# CloudWatch logs
resource "aws_cloudwatch_log_group" "lambda" {
  name              = "/aws/lambda/${aws_lambda_function.main.function_name}"
  retention_in_days = 14
}

# Outputs
output "function_arn" {
  value = aws_lambda_function.main.arn
}

output "function_name" {
  value = aws_lambda_function.main.function_name
}
```

